sql:
SELECT specialty
FROM professionals
WHERE rating = (
    SELECT MAX(rating)
    FROM professionals
);

SELECT first_name, last_name
FROM professionals
WHERE available = 1 AND is_active = 1 AND years_of_experience > 10 AND rating >= 4.5;

external_knowledge:
- 'expert' refers to professionals in various fields (e.g., estate taxes, medical, properties); 
- 'star-studded reputation' means having a high rating (i.e., rating >= 4.5); 
- 'lookalike in the field' implies more than one professional with the same name, specialty, years of experience, and rating; 
- 'most experienced' refers to the highest years of experience.

sql:
SELECT COUNT(*) AS total_professionals
FROM professionals
WHERE rating > 4.5 AND years_of_experience > 5 AND specialty IN ('estate taxes', 'medical');

SELECT first_name, last_name
FROM professionals
WHERE rating = (SELECT MAX(rating) FROM professionals);

SELECT first_name || ' ' || last_name AS full_name
FROM professionals
WHERE is_active = 1 AND rating > (SELECT AVG(rating) FROM professionals);
